<?php
namespace App\Http\Controllers\Api\V1;
use App\Http\Controllers\Controller;use App\Models\Device;use App\Models\DeviceProvisioningToken;use App\Services\AuditService;use Illuminate\Http\Request;use Illuminate\Support\Facades\DB;use Illuminate\Support\Facades\Hash;use Illuminate\Support\Str;
class ProvisioningEnrollmentController extends Controller {
 public function __invoke(Request $r,AuditService $audit){$d=$r->validate(['device_reference'=>['required','uuid'],'provisioning_token'=>['required','string','min:64'],'management_pin'=>['required','digits:4'],'device_uuid'=>['required','uuid'],'android_version'=>['required','string','max:50'],'app_version'=>['required','string','max:50'],'manufacturer'=>['required','string','max:100'],'model'=>['required','string','max:100'],'is_device_owner'=>['required','boolean'],'is_admin_active'=>['required','boolean'],'fcm_token'=>['nullable','string','max:4096']]);$device=Device::where('uuid',$d['device_reference'])->first();$token=DeviceProvisioningToken::where('token_hash',hash('sha256',$d['provisioning_token']))->first();if(!$device||!$token||$token->device_id!==$device->id)return response()->json(['message'=>'Device reference mismatch','error_code'=>'DEVICE_REFERENCE_MISMATCH'],422);if(!$token->usable())return response()->json(['message'=>'Provisioning token is expired, revoked, or already used.','error_code'=>'TOKEN_INVALID'],410);$token->update(['status'=>'waiting_for_pin','provisioning_started_at'=>$token->provisioning_started_at?:now()]);if(!Hash::check($d['management_pin'],$device->management_pin_hash)){ $audit->record('PROVISIONING_PIN_FAILED','Provisioning Management PIN verification failed',null,$device);return response()->json(['message'=>'Incorrect management PIN','error_code'=>'INCORRECT_PIN'],422); }if(!$d['is_device_owner']||!$d['is_admin_active'])return response()->json(['message'=>'Android has not confirmed Device Owner provisioning.','error_code'=>'DEVICE_OWNER_NOT_CONFIRMED'],422);return DB::transaction(function()use($device,$token,$d,$audit){$plain=Str::random(64);$device->update(['device_uuid'=>$d['device_uuid'],'fcm_token'=>$d['fcm_token']??null,'android_version'=>$d['android_version'],'app_version'=>$d['app_version'],'status'=>'active_unlocked','management_mode'=>'managed','management_status'=>'active','is_device_owner'=>true,'is_admin_active'=>true,'last_seen_at'=>now(),'last_sync_at'=>now()]);$token->update(['status'=>'completed','used_at'=>now(),'provisioning_completed_at'=>now()]);$device->tokens()->create(['token_hash'=>hash('sha256',$plain)]);$audit->record('PROVISIONING_COMPLETED','Device Owner QR provisioning completed',null,$device);return response()->json(['message'=>'Full management enrollment completed.','data'=>['device_uuid'=>$device->uuid,'device_token'=>$plain,'command_verification_key'=>hash_hmac('sha256',$device->uuid,config('device.command_signing_key')),'status'=>'active_unlocked']]);});}
}
